class Playground {
    async run(inputs) {
        const inputStr = inputs[0] || "0,1,0,2,1,0,1,3,2,1,2,1";
        const h = inputStr.split(',').map(Number);
        const n = h.length;

        // 1. Initialize data structures
        await this.heights.init(h);
        await this.water.init(new Array(n).fill(0));
        await this.vars.init([
            ["Left", 0],
            ["Right", n - 1],
            ["LeftMax", 0],
            ["RightMax", 0],
            ["TotalWater", 0]
        ]);

        let left = 0;
        let right = n - 1;
        let leftMax = 0;
        let rightMax = 0;
        let totalWater = 0;

        this.log("Starting Two-Pointer approach from both ends.");
        await this.await();

        while (left <= right) {
            // Highlight current pointers
            this.heights.highlight(left, "#00e0ff"); // Cyan for left
            this.heights.highlight(right, "#ffb703"); // Amber for right

            this.vars.put("Left", left);
            this.vars.put("Right", right);

            if (h[left] < h[right]) {
                this.log(`Height[Left] (${h[left]}) < Height[Right] (${h[right]}). Processing Left.`);

                if (h[left] >= leftMax) {
                    leftMax = h[left];
                    this.vars.put("LeftMax", leftMax);
                    this.log(`Updated LeftMax to ${leftMax}`);
                } else {
                    const trapped = leftMax - h[left];
                    totalWater += trapped;
                    await this.water.set(left, trapped);
                    this.vars.put("TotalWater", totalWater);
                    this.log(`Trapped ${trapped} units at index ${left} (LeftMax ${leftMax} - Height ${h[left]})`);
                }

                await this.await();
                // Remove highlight before moving
                this.heights.highlight(left, null);
                left++;
            } else {
                this.log(`Height[Left] (${h[left]}) >= Height[Right] (${h[right]}). Processing Right.`);

                if (h[right] >= rightMax) {
                    rightMax = h[right];
                    this.vars.put("RightMax", rightMax);
                    this.log(`Updated RightMax to ${rightMax}`);
                } else {
                    const trapped = rightMax - h[right];
                    totalWater += trapped;
                    await this.water.set(right, trapped);
                    this.vars.put("TotalWater", totalWater);
                    this.log(`Trapped ${trapped} units at index ${right} (RightMax ${rightMax} - Height ${h[right]})`);
                }

                await this.await();
                // Remove highlight before moving
                this.heights.highlight(right, null);
                right--;
            }
        }

        this.log(`Calculation complete. Total trapped water: ${totalWater}`);
        return totalWater;
    }
}
